using System;
using System.Linq;
using System.Collections.Generic;
using Microsoft.Build.Logging.StructuredLogger;

var binlogPath = args.Length > 0 ? args[0] : "build.binlog";
var build = BinaryLog.ReadBuild(binlogPath);

Console.WriteLine("=== BUILD OVERVIEW ===");
Console.WriteLine($"Build Succeeded: {build.Succeeded}");
Console.WriteLine();

// Collect all errors and warnings
var errors = new List<(string File, int Line, int Col, string Code, string Message, string Project)>();
var warnings = new List<(string File, int Line, int Col, string Code, string Message, string Project)>();

void Visit(BaseNode node)
{
    if (node is Error err)
    {
        errors.Add((err.File ?? "", err.LineNumber, err.ColumnNumber, err.Code ?? "", err.Text ?? err.ToString(), err.ProjectFile ?? ""));
    }
    else if (node is Warning warn)
    {
        warnings.Add((warn.File ?? "", warn.LineNumber, warn.ColumnNumber, warn.Code ?? "", warn.Text ?? warn.ToString(), warn.ProjectFile ?? ""));
    }

    if (node.HasChildren)
    {
        foreach (var child in node.Children.OfType<BaseNode>())
        {
            Visit(child);
        }
    }
}

Visit(build);

Console.WriteLine("=== ERRORS ===");
foreach (var e in errors)
{
    Console.WriteLine($"  [{e.Code}] {e.File}({e.Line},{e.Col}): {e.Message}");
    Console.WriteLine($"    Project: {e.Project}");
    Console.WriteLine();
}

Console.WriteLine($"=== WARNINGS ({warnings.Count}) ===");
foreach (var w in warnings)
{
    Console.WriteLine($"  [{w.Code}] {w.File}({w.Line},{w.Col}): {w.Message}");
    Console.WriteLine($"    Project: {w.Project}");
    Console.WriteLine();
}

// Extract project dependency graph
Console.WriteLine("=== PROJECT STRUCTURE ===");
void VisitProjects(BaseNode node, int depth = 0)
{
    if (node is Project proj)
    {
        var indent = new string(' ', depth * 2);
        var status = proj.Succeeded ? "✓" : "✗";
        Console.WriteLine($"{indent}{status} {proj.Name} ({proj.ProjectFile})");
        Console.WriteLine($"{indent}  Target: {proj.TargetFramework}");

        // Look for project references
        if (node.HasChildren)
        {
            foreach (var child in node.Children.OfType<BaseNode>())
            {
                VisitProjects(child, depth + 1);
            }
        }
    }
    else if (node.HasChildren)
    {
        foreach (var child in node.Children.OfType<BaseNode>())
        {
            VisitProjects(child, depth);
        }
    }
}
VisitProjects(build);

// Look for Items (PackageReferences, ProjectReferences)
Console.WriteLine();
Console.WriteLine("=== ITEM DETAILS (PackageReference / ProjectReference) ===");
void VisitItems(BaseNode node, string currentProject = "")
{
    if (node is Project proj2)
    {
        currentProject = proj2.ProjectFile ?? proj2.Name;
    }

    if (node is NamedNode named && (named.Name == "PackageReference" || named.Name == "ProjectReference"))
    {
        Console.WriteLine($"  [{currentProject}] {named.Name}: {named}");
    }

    if (node is AddItem addItem && (addItem.Name == "PackageReference" || addItem.Name == "ProjectReference"))
    {
        Console.WriteLine($"  [{currentProject}] AddItem {addItem.Name}:");
        if (addItem.HasChildren)
        {
            foreach (var child in addItem.Children)
            {
                Console.WriteLine($"    - {child}");
            }
        }
    }

    if (node.HasChildren)
    {
        foreach (var child in node.Children.OfType<BaseNode>())
        {
            VisitItems(child, currentProject);
        }
    }
}
VisitItems(build);

// Check which projects failed and succeeded
Console.WriteLine();
Console.WriteLine("=== PROJECT BUILD RESULTS ===");
void VisitResults(BaseNode node)
{
    if (node is Project proj3)
    {
        var errCount = 0;
        void CountErrors(BaseNode n)
        {
            if (n is Error) errCount++;
            if (n.HasChildren)
                foreach (var c in n.Children.OfType<BaseNode>())
                    CountErrors(c);
        }
        CountErrors(proj3);
        Console.WriteLine($"  {(proj3.Succeeded ? "PASS" : "FAIL")} | {proj3.Name} | Errors: {errCount} | {proj3.ProjectFile}");
    }
    if (node.HasChildren)
        foreach (var child in node.Children.OfType<BaseNode>())
            VisitResults(child);
}
VisitResults(build);
